import './App.css';
import Dashboard from "./pages/Dashboard/Dashboard";
import Transactions from './pages/Transactions/Transactions';
import Navbar from "./components/Navbar/Navbar";
import { useState, useEffect } from 'react';
import Analytics from './pages/Analytics/Analytics';
import axios from "axios";

function App() {
  const [page, setPage] = useState("Dashboard");
  const [transactions, setTransactions] = useState([]);
  useEffect(()=>{
    axios.get("http://localhost:5000/api/transactions").then((res)=>{
      setTransactions(res.data.transactions);
    })
  },[])
  const [showForm, setShowForm] = useState(false);
  return (
    <>
    <Navbar page={page} setPage={setPage}/>
    {page==='Dashboard' && <Dashboard setTransactions={setTransactions} setShowForm={setShowForm}/>}
    {page==='Transactions' && <Transactions transactions={transactions} setTransactions={setTransactions} showForm={showForm} setShowForm={setShowForm}/>}
    {page==='Analytics' && <Analytics transactions={transactions}/>}
    </>
  );
}

export default App;
